GUISubAnimAlpha = class("GUISubAnimAlpha", GUISubAnim)

function GUISubAnimAlpha:play()
    self.alphaStart = tonumber(self.config.alphaStart)
    self.alphaEnd = tonumber(self.config.alphaEnd)
    self.alpha = self.alphaStart
    self.delta = (self.alphaEnd - self.alphaStart) / self.ticks
end

function GUISubAnimAlpha:update()
    if self.isEnd then
        return
    end

    self.alpha = self.alpha + self.delta
    if self.alpha >= 0 then
        self.window:SetAlpha(self.alpha)
        self:checkEnd()
    end
end

function GUISubAnimAlpha:stop()
    --TODO
end

function GUISubAnimAlpha:checkEnd()
    if self.delta == 0 then
        self.isEnd = true
    else
        if self.delta > 0 then
            self.isEnd = (self.alpha >= self.alphaEnd)
        else
            self.isEnd = (self.alpha <= self.alphaEnd)
        end
    end

    if self.isEnd then
        self.window:SetAlpha(self.alphaEnd)
    end
end

return GUISubAnimAlpha